"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const states=[["Draft","Open checks remain before release."],["Reviewed","Checks are recorded and ready."]];
export default function SidecarPanelShift(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div aria-label="Work state" className="grid grid-cols-2 gap-2">{states.map((state,i)=><button type="button" aria-pressed={active===i} key={state[0]} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{state[0]}</button>)}</div><div className="relative mt-4 overflow-hidden rounded-2xl bg-[#f4f5f6] p-5"><motion.i aria-hidden className="absolute inset-y-0 w-2 bg-[#ff9950]" animate={{left:active?"calc(100% - 8px)":0}} transition={reduced?{duration:0}:{type:"spring",stiffness:290,damping:28}}/><motion.div key={active} initial={{x:active?14:-14,opacity:0}} animate={{x:0,opacity:1}} transition={reduced?{duration:.12}:{type:"spring",stiffness:290,damping:28}}><p className="font-black text-[#111]">{states[active][0]}</p><p className="mt-1 text-sm text-[#4a4a4f]">{states[active][1]}</p></motion.div></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{states[active][0]} view selected.</p></section>}
